import torch
import matplotlib.pyplot as plt
import numpy as np

#  Code for Plots was generated by Chat-GPT


def _to_numpy(x):
    if torch.is_tensor(x):
        return x.detach().cpu().numpy()
    return np.asarray(x)


def _extract_mu_std(mu_dist, std_dist, b_idx: int, dim_idx: int):
    mu_np = _to_numpy(mu_dist)
    std_np = _to_numpy(std_dist)

    if mu_np.ndim == 2:
        mu_val = mu_np[b_idx, dim_idx]
    elif mu_np.ndim == 3:
        mu_val = mu_np[0, b_idx, dim_idx]
    else:
        raise ValueError(f"Unsupported mu_dist shape: {mu_np.shape}")

    if std_np.ndim == 2:
        std_val = std_np[b_idx, dim_idx]
    elif std_np.ndim == 3:
        std_val = std_np[0, b_idx, dim_idx]
    else:
        raise ValueError(f"Unsupported std_dist shape: {std_np.shape}")

    return float(mu_val), max(float(std_val), 1e-6)


def _gaussian_pdf(x: np.ndarray, mu: float, std: float) -> np.ndarray:
    return (1.0 / (std * np.sqrt(2.0 * np.pi))) * np.exp(-0.5 * ((x - mu) / std) ** 2)


def plot_mpo_weight_distribution(
    sampled_actions: torch.Tensor,
    weights: torch.Tensor,
    mu_dist,
    std_dist,
    b_idx: int = 0,
    title: str = "",
    action_low: torch.Tensor = None,
    action_high: torch.Tensor = None,
    show: bool = False,
):
    """
    Plot the MPO weight distribution together with the actor Gaussian for
    the first and last action dimension of one batch element.

    Args:
        sampled_actions: Tensor of shape (N, B, A).
        weights: Tensor of shape (N, B).
        mu_dist: Mean tensor of shape (B, A) or compatible.
        std_dist: Std tensor of shape (B, A) or compatible.
        b_idx: Batch index to visualize.
        title: Figure title.
        action_low: Optional action lower bounds.
        action_high: Optional action upper bounds.
        show: Whether to call plt.show().

    Returns:
        Matplotlib figure.
    """
    assert sampled_actions.ndim == 3, f"Expected sampled_actions shape (N, B, A), got {sampled_actions.shape}"
    assert weights.ndim == 2, f"Expected weights shape (N, B), got {weights.shape}"
    assert sampled_actions.shape[:2] == weights.shape, (
        f"sampled_actions.shape[:2]={sampled_actions.shape[:2]} must match weights.shape={weights.shape}"
    )
    assert 0 <= b_idx < sampled_actions.shape[1], f"b_idx={b_idx} out of range for B={sampled_actions.shape[1]}"

    with torch.no_grad():
        actions_np = sampled_actions.detach().cpu().numpy()
        weights_np = weights.detach().cpu().numpy()

        x_first = actions_np[:, b_idx, 0]
        x_last = actions_np[:, b_idx, -1]
        y = weights_np[:, b_idx]

        fig, axes = plt.subplots(1, 2, figsize=(12, 4))
        fig.suptitle(title if title else f"MPO weight distribution for batch sample {b_idx}")

        for ax, x, dim_name, dim_idx in [
            (axes[0], x_first, "First actor dimension", 0),
            (axes[1], x_last, "Last actor dimension", sampled_actions.shape[-1] - 1),
        ]:
            order = x.argsort()
            x_plot = x[order]
            y_plot = y[order]

            mu_val, std_val = _extract_mu_std(mu_dist, std_dist, b_idx, dim_idx)

            x_min = float(np.min(x_plot))
            x_max = float(np.max(x_plot))

            low_val = None
            high_val = None

            if action_low is not None:
                low_val = action_low[dim_idx].detach().cpu().item() if torch.is_tensor(action_low) else action_low[dim_idx]
                x_min = min(x_min, float(low_val))

            if action_high is not None:
                high_val = action_high[dim_idx].detach().cpu().item() if torch.is_tensor(action_high) else action_high[dim_idx]
                x_max = max(x_max, float(high_val))

            x_dense = np.linspace(x_min, x_max, 400)
            pdf_dense = _gaussian_pdf(x_dense, mu_val, std_val)

            ax.plot(
                x_dense,
                pdf_dense,
                linestyle="--",
                linewidth=2.0,
                alpha=0.9,
                zorder=1,
                label=f"Actor Gaussian (mu={mu_val:.2f}, std={std_val:.2f})",
            )

            ax.scatter(
                x_plot,
                y_plot,
                alpha=0.8,
                s=20,
                zorder=3,
                label="MPO weights",
            )
            ax.plot(
                x_plot,
                y_plot,
                alpha=0.6,
                zorder=2,
            )

            if low_val is not None:
                ax.axvline(low_val, linestyle="--", alpha=0.7, label="action_low")

            if high_val is not None:
                ax.axvline(high_val, linestyle="--", alpha=0.7, label="action_high")

            ax.set_xlabel(f"Action value ({dim_name})")
            ax.set_ylabel("Weight / Density")
            ax.set_title(dim_name)
            ax.grid(True, alpha=0.3)
            ax.legend()

        plt.tight_layout()

        if show:
            plt.show()

        return fig
